      "subtask": "Extract the largest negative and smallest positive",
      "atomics": [
        "Find the maximum value from negatives, or None if empty",
        "Find the minimum value from positives, or None if empty"
      ]
    },
    {
      "subtask": "Return the result as a tuple",
      "atomics": [
        "Construct and return tuple (largest_negative, smallest_positive)"
      ]
    }
