  "global": "Use list comprehension to filter by sign, apply max/min with None fallback, return (a, b) tuple.",
  "subtasks": [
    {
      "subtask": "Create negative and positive sublists using comprehension",
      "atomics": [
        "Assign negatives = [x for x in lst if x < 0]",
        "Assign positives = [x for x in lst if x > 0]"
      ]
    },
    {
      "subtask": "Compute largest negative and smallest positive with None fallback",
      "atomics": [
        "Assign a = max(negatives) if negatives else None",
        "Assign b = min(positives) if positives else None"
      ]
    },
    {
      "subtask": "Return the result tuple",
      "atomics": [
        "Return (a, b)"
      ]
    }
  ],
  "global_atomics": [
    "Confirm filtering uses x < 0 and x > 0 to exclude zero from both categories",
    "Assert return value equals (None, 1) for [2,4,1,3,5,7], (None, None) for [], (None, None) for [0]"
  ]
}

